    if (f.op === 'below') return isFinite(a) && v < a;
    if (f.op === 'outside') return isFinite(a) && isFinite(b) && (v < a || v > b);
    if (f.op === 'inside') return isFinite(a) && isFinite(b) && v >= a && v <= b;
    return false;
