  const label = ROW_META[ec] ? ROW_META[ec](rec).title : String(hit.recId);
  const m = commentMarker(rec);
  newChat({ id: 'TAG:' + ec + ':' + hit.recId, label, color: m ? m.color : 'gray', ref: { card: ec, recId: hit.recId } });
