  const html = DATA.categories.map((k) =>
    `<button class="dd-item js-setintcat ${have.has(k.categoryId) ? 'on' : ''}" data-rec="${esc(custId)}" data-val="${esc(k.categoryId)}">${esc(k.name)}</button>`).join('');
