async function autofillPartLine(w, li, photo) {
  if (!w || !li) return;
  const sys = `You are Mr. Wrangler reading a photo of an equipment part, tool, or repair item for a heavy-equipment rental shop. Extract these fields: description (a short part or task name), cost (price each — a number in dollars, no symbol), hours (labor hours to install or complete it — a number), url (a product or order link if one is visible), vendor (the supplier's business name). Respond with ONLY a JSON object using those exact keys; omit any key you cannot read confidently. No prose, no code fences.`;
  const d = await wranglerExtract(photo, sys); if (!d || typeof d !== 'object') return;
  const ph = '📷 Awaiting Mr. Wrangler review';
  let changed = false;
  if ((!li.part || li.part === ph) && d.description) { li.part = String(d.description); changed = true; }
  if (!(li.cost > 0) && d.cost != null && !isNaN(Number(d.cost))) { li.cost = Number(d.cost); changed = true; }
  if (!(li.hours > 0) && d.hours != null && !isNaN(Number(d.hours))) { li.hours = Number(d.hours); changed = true; }
  if (!li.url && d.url) { li.url = String(d.url); changed = true; }
  if (!li.vendorId && d.vendor) { li.vendorId = vendorIdByName(d.vendor); changed = true; }
  if (!changed) return;
  li.aiPending = !li.part || li.part === ph || !(li.cost > 0) || !(li.hours > 0);
  // sync to / create the catalog part (mirror savePartForm: link → name-match → create)
  let p = li.partId ? DATA.parts.find((r) => r.partId === li.partId) : null;
  if (!p && li.part && li.part !== ph) p = DATA.parts.find((r) => (r.name || '').toLowerCase() === li.part.toLowerCase());   // name-match before create (no dup)
  if (p) {
    if (li.part && li.part !== ph) p.name = li.part;
    if (li.cost > 0) p.priceEach = li.cost;
    if (li.url) p.website = li.url;
    if (li.vendorId) p.vendorId = li.vendorId;
    if (!li.aiPending) p.aiPending = false;
    li.partId = p.partId; reindex('parts', p);
  } else if (li.part && li.part !== ph) {
    p = { partId: 'PRT-C' + (state.seq++), name: li.part, status: 'Catalog', priceEach: li.cost > 0 ? li.cost : null, qtyOnHand: null, website: li.url || '', orderEmail: '', productNumber: '', vendorId: li.vendorId || null, imageUrl: '', notes: '', woId: w.woId, aiPending: li.aiPending, mock: true };
    DATA.parts.push(p); li.partId = p.partId; reindex('parts', p);
  }
  reindex('workOrders', w); logAction(w, '✨ Mr. Wrangler filled a part line from the photo'); saveSoon();
  reanchorRender(); if (state.overlay?.kind === 'board') renderOverlay();
  toast('✨ Mr. Wrangler filled in the part.');
}

function savePartForm() {
  const o = state.overlay; if (!o || o.kind !== 'partform') return;
  const w = IDX.wo.get(o.woId); if (!w) return closeOverlay();
  const g = (c) => (document.querySelector(c)?.value || '').trim();
  const desc = g('.js-pf2-desc'), cost = g('.js-pf2-cost'), hours = g('.js-pf2-hours'), url = g('.js-pf2-url'), vendor = g('.js-pf2-vendor');
  if (!desc && !state.partPhoto) return attnFlash('.js-pf2-desc, .file-drop');   // R19: need a name OR a photo for the AI
  w.lineItems = w.lineItems || [];
  const li = o.idx != null ? w.lineItems[o.idx] : { phase: 'Part Needed?', eta: '' };
  if (!li) return closeOverlay();                  // stale edit index — the line was removed after the popup opened
  li.part = desc || li.part || '📷 Awaiting Mr. Wrangler review';
  li.cost = cost !== '' ? Number(cost) || 0 : (li.cost || 0);
  li.hours = hours !== '' ? Number(hours) || 0 : (li.hours || 0);
  li.url = url || li.url || '';
  if (state.partPhoto) li.photo = state.partPhoto;
  li.aiPending = !desc || cost === '' || hours === '';
  if (vendor) {
    let v = DATA.vendors.find((x) => (x.name || '').toLowerCase() === vendor.toLowerCase());
    if (!v) { v = { vendorId: 'VEN-C' + (state.seq++), name: vendor, mock: true }; DATA.vendors.push(v); reindex('vendors', v); }
    li.vendorId = v.vendorId;
  }
  if (desc) {
    let p = li.partId ? DATA.parts.find((r) => r.partId === li.partId) : null;   // the li↔part link (stamped below) survives renames
    if (!p) p = DATA.parts.find((r) => (r.name || '').toLowerCase() === desc.toLowerCase());
    if (!p) {
      p = { partId: 'PRT-C' + (state.seq++), name: desc, status: 'Catalog', priceEach: cost !== '' ? Number(cost) || 0 : null, qtyOnHand: null, website: url || '', orderEmail: '', productNumber: '', vendorId: li.vendorId || null, imageUrl: '', notes: '', woId: w.woId, aiPending: li.aiPending, mock: true };
      DATA.parts.push(p);
    } else {
      // write-back (was create-only): edited name/cost/url/vendor on the WO line sync to the catalog part
      if (p.name !== desc) { logAction(p, `Renamed via WO line: ${auditVal(p.name)} → ${auditVal(desc)}`); p.name = desc; }
      if (cost !== '') p.priceEach = Number(cost) || 0;
      if (url) p.website = url;
      if (li.vendorId) p.vendorId = li.vendorId;
      if (!li.aiPending) p.aiPending = false;   // blanks filled — clear the ✨
    }
    li.partId = p.partId;   // forward link: exact USED-ON + rename-safe sync
    reindex('parts', p);
  }
  if (o.idx == null) w.lineItems.push(li);
  if (w.phase === 'Complete') w.phase = 'Part Needed?';
  reindex('workOrders', w); logAction(w, `${o.idx != null ? 'Edited' : 'Added'} line: ${auditVal(li.part)}`);
  const photo = li.photo || null;   // §18g — capture for the AI photo-autofill before state clears
  state.partPhoto = null; state.overlay = null;
  const willFill = li.aiPending && photo && typeof backendPassword !== 'undefined' && backendPassword;
  toast(willFill ? '✨ Saved — Mr. Wrangler is reading the photo to fill the blanks…' : li.aiPending ? '✨ Saved — add a photo and Mr. Wrangler can fill the blanks.' : 'Line saved.');
  reanchorRender(); renderOverlay();
  // Offload the line photo to Drive (de-bloat) — but Mr. Wrangler reads the
  // in-memory base64 FIRST, so chain the offload after the autofill resolves.
  const offloadLinePhoto = () => { if (photo) offloadPhoto(li, 'photo', 'wopart_' + w.woId + '_' + lineKey(li), w, 'workOrders'); };
  if (willFill) autofillPartLine(w, li, photo).then(offloadLinePhoto, offloadLinePhoto); else offloadLinePhoto();   // §18g fire-and-forget photo autofill (offload even if the AI read fails)
}
/* Receipt popup save (§7.11): creates/updates the expense; vendor name-match or
   auto-create (the savePartForm idiom); empty AI-fillable fields flag aiPending ✨;
   lands ON the new detail in the expenses board popup. */
function saveReceiptForm() {
  const o = state.overlay; if (!o || o.kind !== 'receiptform') return;
  const g = (c) => (document.querySelector(c)?.value || '').trim();
  const venName = g('.js-rf-vendor'), amt = g('.js-rf-amount'), date = o.date || TODAY_ISO, partName = g('.js-rf-part');
  const existing = o.expenseId != null ? (IDX.expense.get(o.expenseId) || DATA.expenses.find((r) => r.expenseId === o.expenseId)) : null;
  if (amt === '' && !state.receiptPhoto && !existing?.photo) return attnFlash('.js-rf-amount, .file-drop');   // R19: need a $cost OR a photo for the AI
  const rec = existing || { expenseId: 'E-NEW' + (state.seq++), vendorId: null, date: TODAY_ISO, amount: 0, reconcile: 'Unreconciled', method: 'Cash', category: 'Parts', woId: null, notes: '', mock: true };
  if (venName) {
    let v = DATA.vendors.find((r) => (r.name || '').toLowerCase() === venName.toLowerCase());
    if (!v) { v = { vendorId: 'VEN-C' + (state.seq++), name: venName, mock: true }; DATA.vendors.push(v); reindex('vendors', v); }
    rec.vendorId = v.vendorId;
  }
  if (amt !== '') rec.amount = Number(amt) || 0;
  if (date) rec.date = date;
  if (state.receiptPhoto) rec.photo = state.receiptPhoto;
  rec.aiPending = !venName || amt === '';
  if (!existing) DATA.expenses.push(rec);
  // Part Name (Jac 2026-06-12): name-match or create the part and reconcile it
  // against this receipt — the $cost seeds priceEach on a fresh part.
  if (partName) {
    let p = DATA.parts.find((r) => (r.name || '').toLowerCase() === partName.toLowerCase());
    if (!p) { p = { partId: 'PRT-C' + (state.seq++), name: partName, status: 'Catalog', priceEach: amt !== '' ? Number(amt) || 0 : null, qtyOnHand: null, website: '', orderEmail: '', productNumber: '', vendorId: rec.vendorId || null, imageUrl: '', notes: '', mock: true }; DATA.parts.push(p); }
    p.receiptId = rec.expenseId; p.receiptQty = p.receiptQty || 1;
    reindex('parts', p); logAction(rec, `Linked part: ${partName}`);
  }
  reindex('expenses', rec); logAction(rec, existing ? 'Receipt edited' : 'Receipt created');
  const photo = rec.photo || null;   // §18g — capture for the AI photo-autofill before state clears
  state.receiptPhoto = null;
  openOverlay({ kind: 'board', board: 'expenses', recId: rec.expenseId });   // save lands ON the detail
  const willFill = rec.aiPending && photo && typeof backendPassword !== 'undefined' && backendPassword;
  toast(willFill ? '✨ Saved — Mr. Wrangler is reading the photo to fill the blanks…' : rec.aiPending ? '✨ Saved — add a receipt photo and Mr. Wrangler can fill the blanks.' : 'Receipt saved.');
  render();
  attnFlash('.board-detail .detail-head');   // R19: glow the fresh receipt
  if (willFill) autofillReceipt(rec, photo);   // §18g fire-and-forget photo autofill
}
/* Reconcile link (§7.11): name-match an existing part or create one, then stamp
   part.receiptId/receiptQty (the part points at the receipt — ONE SOURCE, ONE HOME).
   At $0 Unaccounted the gate is SUGGESTED via R19 flash — never auto-flipped. */
function saveReceiptPartLink(expenseId) {
  const x = IDX.expense.get(expenseId) || DATA.expenses.find((r) => r.expenseId === expenseId); if (!x) return;
  const g = (c) => (document.querySelector(c)?.value || '').trim();
  const name = g('.js-rp-name'), qty = Math.max(1, Number(g('.js-rp-qty')) || 1), cost = g('.js-rp-cost');
  if (!name) return attnFlash('.js-rp-name');   // R19
  let p = DATA.parts.find((r) => (r.name || '').toLowerCase() === name.toLowerCase());
  if (!p) { p = { partId: 'PRT-C' + (state.seq++), name, status: 'Catalog', priceEach: cost !== '' ? Number(cost) || 0 : null, qtyOnHand: null, website: '', orderEmail: '', productNumber: '', vendorId: x.vendorId || null, imageUrl: '', notes: '', mock: true }; DATA.parts.push(p); }
  else if (cost !== '') p.priceEach = Number(cost) || 0;
  p.receiptId = x.expenseId; p.receiptQty = qty;
  reindex('parts', p);
  logAction(x, `Linked part: ${name} ×${qty}`);
  if (state.overlay?.kind === 'board') state.overlay.partForm = false;
  render(); renderOverlay();
  const un = (Number(x.amount) || 0) - receiptLineTotal(x.expenseId);
  if (Math.abs(un) < 0.005 && x.reconcile !== 'Reconciled') attnFlash(`.js-reconcile[data-rec="${x.expenseId}"]`);   // R19: $0 left — suggest the gate
}
function unlinkReceiptPart(expenseId, partId) {
  const x = IDX.expense.get(expenseId) || DATA.expenses.find((r) => r.expenseId === expenseId);
  const p = DATA.parts.find((r) => r.partId === partId);
  if (!x || !p) return;
  p.receiptId = null; p.receiptQty = null;
  reindex('parts', p);
  logAction(x, `Unlinked part: ${p.name}`);
  render(); renderOverlay();
}
/* +File inline create (§7.13): name + optional link, every other field deferred to
   inline edit on the detail. The saveReceiptForm idiom: save lands ON the new
   detail + R19 glow; Cancel leaves no stub. */
async function saveFileForm() {
  const o = state.overlay; if (!o || o.kind !== 'board' || o.board !== 'files') return;
  const g = (c) => (document.querySelector(c)?.value || '').trim();
  const name = g('.js-ff-name'), link = g('.js-ff-link');
  const up = o.fileUpload;
  if (!name && !up && !link) return attnFlash('.js-ff-name');   // R19 — need at least a name, a file, or a link
  const fname = name || (up && up.name) || 'File';
  const isImg = !!(up && (up.mimeType || '').startsWith('image/'));
  let fileLink = link, inlinePhoto = '', driveId = '';
  if (up) {
    if (typeof backendPassword !== 'undefined' && backendPassword) {
      // live → the backend stores the file in Drive and returns a shareable link (§F2)
      try {
        const r = await backendCall('uploadFile', { name: fname, mimeType: up.mimeType, data: up.data });
        if (r && r.ok && r.url) { fileLink = r.url; driveId = r.fileId || ''; }
        else { toast('Upload failed: ' + ((r && r.error) || 'backend not ready')); return; }
      } catch (err) { toast('Upload failed — check the connection.'); return; }
    } else if (isImg) {
      inlinePhoto = up.data;   // demo (#local): keep the downscaled image inline so the flow is reviewable
    } else {
      toast('Demo mode — document uploads land in Drive on the live site.');
    }
  }
  const f = { fileId: 'FIL-C' + (state.seq++), name: fname, group: '', type: up ? (isImg ? 'Photo' : 'Document') : (link ? 'Link' : 'Note'), reviewByDate: '', link: fileLink, photo: inlinePhoto, driveId, notes: '', mock: true };
  DATA.companyFiles.push(f); reindex('files', f);   // reindex also sets IDX.file (sync clause)
  logAction(f, 'File created');
  o.fileForm = false; o.fileUpload = null; o.recId = f.fileId;   // save lands ON the new detail
  render(); renderOverlay();
  attnFlash('.board-detail .detail-head');  // R19: glow the fresh file
}
function completeWOAttempt(woId) {
  const w = IDX.wo.get(woId); if (!w) return;
  const open = (w.lineItems || []).filter((l) => l.phase !== 'Complete');
  if (!open.length) return setWoPhase(woId, 'Complete');
  openOverlay({ kind: 'wodone', woId });           // "Are you sure? Not all items are completed."
}

function onInput(e) {
  if (e.target.id === 'globalsearch') {
    const sel = e.target.selectionStart;
    setQuery(e.target.value);                      // re-renders; the input is recreated
    const gs = document.getElementById('globalsearch');
    if (gs) { gs.focus(); gs.setSelectionRange(sel, sel); }
    return;
  }
  if (e.target.classList.contains('js-history-search')) {
    if (state.overlay?.kind === 'board') {   // vendor detail in the board popup — history search rides the overlay state
      state.overlay.historySearch = e.target.value;
      const sel = e.target.selectionStart; renderOverlay();
      const hs = document.querySelector('.overlay .js-history-search'); if (hs) { hs.focus(); hs.setSelectionRange(sel, sel); }
      return;
    }
    const card = e.target.closest('.card')?.dataset.card; if (!card) return;
    activeSession().cards[card].historySearch = e.target.value;
    const sel = e.target.selectionStart; render();
    const hs = document.querySelector(`.card[data-card="${card}"] .js-history-search`); if (hs) { hs.focus(); hs.setSelectionRange(sel, sel); }
    return;
  }
  if (e.target.classList.contains('mini-search')) {
    const card = e.target.dataset.card; const mcs = activeSession().cards[card]; mcs.search = e.target.value; mcs.listLimit = undefined;
    // light re-render of just that card would be ideal; full render is fine at seed scale
    const sel = e.target.selectionStart; render();
    const ms = document.querySelector(`.mini-search[data-card="${card}"]`); if (ms) { ms.focus(); ms.setSelectionRange(sel, sel); }
    return;
  }
  // Feedback description → store as they type (so a re-render keeps it).
  if (e.target.classList.contains('js-fb-text')) { if (state.overlay?.kind === 'feedback') state.overlay.text = e.target.value; return; }
  if (e.target.classList.contains('js-cmt-text')) { if (state.overlay?.kind === 'comment') state.overlay.text = e.target.value; return; }
  if (e.target.classList.contains('js-wr-in')) { if (state.wrangler.open) state.wrangler.draft = e.target.value; return; }
  if (e.target.classList.contains('chat-input')) { state.chat.draft = e.target.value; return; }
  // Company Files live search → re-render the board popup and restore the caret.
  if (e.target.classList.contains('js-files-query')) {
    if (state.overlay?.kind === 'board') { state.overlay.fileSearch = e.target.value; const sel = e.target.selectionStart; renderOverlay(); const q = document.querySelector('.js-files-query'); if (q) { q.focus(); q.setSelectionRange(sel, sel); } }
    return;
  }
  // Board View live search → re-render the popup and restore the caret.
  if (e.target.classList.contains('bv-query')) {
    if (state.overlay?.kind === 'boardview') { state.overlay.query = e.target.value; const sel = e.target.selectionStart; renderOverlay(); const q = document.querySelector('.bv-query'); if (q) { q.focus(); q.setSelectionRange(sel, sel); } }
    return;
  }
  // Board View formula/notes-column header (store only — no re-render, keep focus).
  if (e.target.classList.contains('bv-colname')) {
    const o = state.overlay; if (o?.kind === 'boardview') { const ec = (o.colOrder || []).find((x) => x.kind === 'extra' && x.id === e.target.dataset.col); if (ec) ec.label = e.target.value; }
    return;
  }
  // Board View scratch cell (contenteditable) → persist into the overlay's formula store.
  if (e.target.classList.contains('bv-scratch') && e.target.isContentEditable) {
    const o = state.overlay; if (o?.kind === 'boardview') {
      const val = e.target.textContent;
      if (e.target.dataset.srow) { const er = (o.extraRows || []).find((x) => x.id === e.target.dataset.srow); if (er) { er.cells = er.cells || {}; er.cells[e.target.dataset.col] = val; } }
      else if (e.target.dataset.row) { o.cellData = o.cellData || {}; (o.cellData[e.target.dataset.row] = o.cellData[e.target.dataset.row] || {})[e.target.dataset.col] = val; }
    }
    return;
  }
}

/* change events — native <input type="date"> / <select> on draft details. */
function onChange(e) {
  // Settings Board — relabel a status (commit on blur/enter; the value/role stays locked)
  if (e.target.classList.contains('js-set-label')) {
    const o = state.overlay; if (!o) return;
    const def = (STATUS_DEFAULTS[e.target.dataset.set] || {})[e.target.dataset.val] || {};
    const v = e.target.value.trim();
    setDraftStatus(o, e.target.dataset.set, e.target.dataset.val, { label: (v && v !== def.label) ? v : '' });
    renderOverlay(); return;
  }
  // Settings Board — Company identity (commit on blur)
  if (e.target.classList.contains('js-co-field')) {
    const o = state.overlay; if (!o) return;
    o.draftSettings = o.draftSettings || {}; o.draftSettings.company = o.draftSettings.company || { ...((state.settings && state.settings.company) || {}) };
    const f = e.target.dataset.f, raw = e.target.value.trim();
    if (f === 'revenueGoal') { const n = Number(raw.replace(/[^0-9.]/g, '')); o.draftSettings.company.revenueGoal = (raw && isFinite(n) && n > 0) ? n : undefined; }
    else if (f === 'maxNetDays') { const n = Math.round(Number(raw.replace(/[^0-9.]/g, ''))); o.draftSettings.company.maxNetDays = (raw && isFinite(n) && n >= 0) ? n : undefined; }
    else if (/^mem[A-Z]/.test(f)) { const n = Number(raw.replace(/[^0-9.]/g, '')); o.draftSettings.company[f] = (raw && isFinite(n) && n >= 0) ? n : undefined; }   // membership pricing — numeric, Owner-settable (spec §2)
    else o.draftSettings.company[f] = raw || undefined;
    renderOverlay(); return;
  }
  // Settings Board — KPI ring label / target (commit on blur)
  if (e.target.classList.contains('js-insp-label')) { const o = state.overlay; if (o) { if (o.inspDraft && typeof o.inspDraft === 'object') o.inspDraft.label = e.target.value; else o.inspDraft = { label: e.target.value, type:'toggle', fail: inspFailDefault('toggle'), options:[] }; } return; }
  if (e.target.classList.contains('js-insp-opt-label')) { const o = state.overlay; if (o && o.inspDraft) o.inspDraft.optLabel = e.target.value; return; }
  if (e.target.classList.contains('js-insp-faila')) { const o = state.overlay; if (o) { o.inspDraft = o.inspDraft || {}; o.inspDraft.fail = { ...(o.inspDraft.fail || {}), a: e.target.value }; } return; }
  if (e.target.classList.contains('js-insp-failb')) { const o = state.overlay; if (o) { o.inspDraft = o.inspDraft || {}; o.inspDraft.fail = { ...(o.inspDraft.fail || {}), b: e.target.value }; } return; }
  if (e.target.classList.contains('js-insp-failval')) { const o = state.overlay; if (o) { o.inspDraft = o.inspDraft || {}; o.inspDraft.fail = { ...(o.inspDraft.fail || {}), value: e.target.value }; } return; }
  if (e.target.classList.contains('js-insp-datev')) { const o = state.overlay; if (o) { o.inspDraft = o.inspDraft || {}; o.inspDraft.fail = { ...(o.inspDraft.fail || {}), ref: e.target.value }; } return; }
  if (e.target.classList.contains('js-ck-input')) { const o = state.overlay; if (o && o.kind === 'checklist') { const n = IDX.insp.get(o.inspId); if (n) { n.items = n.items || {}; n.items[e.target.dataset.id] = e.target.value; } } return; }
  if (e.target.classList.contains('js-kpi-lbl')) { const o = state.overlay; if (!o) return; const rings = ensureKpiDraft(o, e.target.dataset.role); rings[Number(e.target.dataset.i)].label = e.target.value.trim(); renderOverlay(); return; }
  if (e.target.classList.contains('js-kpi-tgt')) { const o = state.overlay; if (!o) return; const rings = ensureKpiDraft(o, e.target.dataset.role); const n = Number(e.target.value); rings[Number(e.target.dataset.i)].target = isFinite(n) && e.target.value.trim() ? n : undefined; renderOverlay(); return; }
  // F2 — +File upload: read the chosen photo/document; images are downscaled, others kept
  // as-is. Held in state.overlay.fileUpload until "Add file" (which sends it to Drive).
  if (e.target.classList.contains('js-ff-file')) {
    const f = e.target.files && e.target.files[0]; if (!f) return;
    if (f.size > 12 * 1024 * 1024) { toast('That file is over 12 MB — use a smaller file or paste a link.'); return; }
    const rd = new FileReader();
    rd.onload = () => {
      const hold = (data) => { if (state.overlay) state.overlay.fileUpload = { name: f.name, mimeType: f.type || 'application/octet-stream', data }; renderOverlay(); };
      if ((f.type || '').startsWith('image/')) downscaleImage(rd.result, 1400, 0.72, (out) => hold(out || rd.result));
      else hold(rd.result);
    };
    rd.onerror = () => toast('Could not read that file.');
    rd.readAsDataURL(f); return;
  }
  // E2 — set/change an invoice's due date inline on the card
  if (e.target.classList.contains('js-due-date')) {
    const inv = IDX.invoice.get(e.target.dataset.rec);
    if (inv) { inv.dueDate = e.target.value || ''; reindex('invoices', inv); toast(inv.dueDate ? `Due date set to ${fmtShortDate(inv.dueDate)}.` : 'Due date cleared.'); render(); }
    return;
  }
  // Part/Task popup photo
  if (e.target.classList.contains('js-pf2-file')) {
    const f = e.target.files && e.target.files[0]; if (!f) return;
    const rd = new FileReader();
    rd.onload = () => { downscaleImage(rd.result, 600, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } state.partPhoto = out; renderOverlay(); }); };
    rd.onerror = () => toast('Could not read that image.');
    rd.readAsDataURL(f);
    return;
  }
  // Receipt popup photo (mirrors js-pf2-file — downscale per the 50k Sheets-cell rule)
  if (e.target.classList.contains('js-rf-file')) {
    const f = e.target.files && e.target.files[0]; if (!f) return;
    const rd = new FileReader();
    rd.onload = () => { downscaleImage(rd.result, 600, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } state.receiptPhoto = out; renderOverlay(); }); };
    rd.onerror = () => toast('Could not read that image.');
    rd.readAsDataURL(f);
    return;
  }
  // v2 yard capture: attach the video/photo, re-render the popup to show ✓
  if (e.target.classList.contains('js-cap-file')) {
    const f = e.target.files && e.target.files[0]; if (!f) return;
    const rd = new FileReader();
    rd.onload = () => { state.capFile = rd.result; renderOverlay(); };
    rd.onerror = () => toast('Could not read that file.');
    rd.readAsDataURL(f);
    return;
  }
  // Feedback screenshot attach → downscale → store on the overlay.
  if (e.target.classList.contains('js-fb-shot')) {
    const file = e.target.files && e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => { downscaleImage(reader.result, 1000, 0.6, (out) => { if (!out) { toast('Could not read that image.'); return; } if (state.overlay?.kind === 'feedback') { state.overlay.shot = out; renderOverlay(); } }); };
    reader.readAsDataURL(file);
    return;
  }
  if (e.target.classList.contains('js-disp-time')) {   // §2.3 dispatch stop time (per-device)
    const t = dispatchTimesLS(); const v = e.target.value.trim(); t[e.target.dataset.id] = v; _lsSave('jactec.dispatchTimes', t);
    if (e.target.closest('.disprail') && timeToMin(v) != null) render();   // cockpit: a complete time re-sorts the token on the rail = retime/reorder
    return;
  }
  if (e.target.classList.contains('js-wr-file')) {   // §18d Mr. Wrangler attach — image or CSV/text
    [...(e.target.files || [])].forEach((f) => wranglerAttachAny(f));
    e.target.value = '';
    return;
  }
  // Board View summary aggregation calc (Sum/Avg/Min/Max/Count) per column.
  if (e.target.classList.contains('bv-calc')) {
    const o = state.overlay; if (o?.kind === 'boardview') { o.calc = o.calc || {}; o.calc[e.target.dataset.col] = e.target.value; renderOverlay(); }
    return;
  }
  // Board View "List rows" picker → toggle a column into/out of List-View row1/row2.
  if (e.target.classList.contains('js-bv-pick')) {
    const card = e.target.dataset.card, row = e.target.dataset.row, col = e.target.dataset.col;
    const layout = loadListLayout(card) || defaultLayoutFor(card);
    layout.row1 = (layout.row1 || []).slice(); layout.row2 = (layout.row2 || []).slice();
    const arr = layout[row];
    if (e.target.checked) {
      if (!arr.includes(col)) { if (arr.length >= 6) { e.target.checked = false; toast('Max 6 per row.'); return; } arr.push(col); }
    } else { const i = arr.indexOf(col); if (i >= 0) arr.splice(i, 1); }
    const nameKey = (CARD_COLUMNS[card] || [])[0]?.key;   // Name stays as the locked title
    if (nameKey && !layout.row1.includes(nameKey)) layout.row1.unshift(nameKey);
    saveListLayout(card, layout);
    render(); renderOverlay();
    return;
  }
  // Customer form selfie: capture (phone camera via capture="user", or upload) → compress → store.
  if (e.target.classList.contains('js-nc-selfie')) {
    const file = e.target.files && e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => { downscaleImage(reader.result, 340, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } ncSyncInputs(); if (state.overlay) { state.overlay.draft.selfie = out; renderOverlay(); } }); };
    reader.readAsDataURL(file);
    return;
  }
  // §7.1c per-card selfie — auto-saves onto the card (or held pre-card) the moment it's captured.
  if (e.target.classList.contains('js-ncsign-selfie')) {
    const file = e.target.files && e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => { downscaleImage(reader.result, 340, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } const o = state.overlay; if (o && o.kind === 'newCustomer') { captureSelfie(o, out); renderOverlay(); } }); };
    reader.readAsDataURL(file);
    return;
  }
  // New Customer form: filling Company auto-promotes Non-Business → Business.
  if (e.target.dataset && e.target.dataset.f && state.overlay?.kind === 'newCustomer') {
    const o = state.overlay, root = document.querySelector('.overlay .popup-body');
    if (root) root.querySelectorAll('[data-f]').forEach((i) => { o.draft[i.dataset.f] = i.value.trim(); });
    ncApplyName(o.draft);
    // quick-add: First + Phone present → persist behind the scenes (no render, keeps focus)
    if (!o.editId) quickSaveCustomer(o);
    // already saved → keep the record live as they keep typing (no render)
    if (o.editId) { const c = IDX.customer.get(o.editId); if (c) { const d = o.draft; Object.assign(c, { firstName: d.firstName, lastName: d.lastName, name: `${d.firstName} ${d.lastName}`.trim(), company: d.company, phone: d.phone, email: d.email, industry: d.industry, accountNotes: d.accountNotes }); reindex('customers', c); } }
    if (o.draft.company && o.draft.accountType === 'Non-Business') { o.draft.accountType = 'Business'; renderOverlay(); }
    return;
  }
  if (e.target.classList.contains('js-insp-photo')) {
    const file = e.target.files && e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => { downscaleImage(reader.result, 600, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } const n = IDX.insp.get(e.target.dataset.rec); if (n) { n.photo = out; saveSoon(); render(); if (state.overlay?.kind === 'inspection') renderOverlay(); offloadPhoto(n, 'photo', 'insp_' + n.inspectionId, n, 'inspections'); } }); };
    reader.onerror = () => toast('Could not read that image.');
    reader.readAsDataURL(file);
    return;
  }
  if (e.target.classList.contains('js-insp-desc')) { const n = IDX.insp.get(e.target.dataset.rec); if (n) { n.description = e.target.value; render(); } return; }
  if (e.target.classList.contains('js-ck-file')) { const file = e.target.files && e.target.files[0]; if (!file) return; if ((file.type||'').startsWith('video/')) { toast('Videos can’t be stored — attach a photo instead.'); return; } const id = e.target.dataset.id; const reader = new FileReader(); reader.onload = () => { downscaleImage(reader.result, 600, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } const o = state.overlay; if (o && o.kind === 'checklist') { const n = IDX.insp.get(o.inspId); if (n) { n.items = n.items || {}; n.items[id] = out; saveSoon(); renderOverlay(); } } }); }; reader.onerror = () => toast('Could not read that image.'); reader.readAsDataURL(file); return; }
  // Per-item photo EVIDENCE (Jac 2026-06-26) — image-only, downscaled, stored inline on the
  // record (n.itemEvidence[id]); mirrors js-ck-file. No Drive offload (inherits the inline pattern).
  if (e.target.classList.contains('js-ck-evid')) { const file = e.target.files && e.target.files[0]; if (!file) return; if ((file.type||'').startsWith('video/')) { toast('Per-item evidence is photo-only — use the walkaround for video.'); return; } const id = e.target.dataset.id; const reader = new FileReader(); reader.onload = () => { downscaleImage(reader.result, 800, 0.6, (out) => { if (!out) { toast('Could not read that image.'); return; } const o = state.overlay; if (o && o.kind === 'checklist') { const n = IDX.insp.get(o.inspId); if (n) { n.itemEvidence = n.itemEvidence || {}; (n.itemEvidence[id] = n.itemEvidence[id] || []).push({ kind: 'image', url: out }); logAction(n, 'Evidence photo attached'); saveSoon(); renderOverlay(); } } }); }; reader.onerror = () => toast('Could not read that image.'); reader.readAsDataURL(file); return; }
  // Unit-level WALKAROUND evidence (Jac 2026-06-26) — image OR video, kept inline on n.evidence
  // (video uncompressed, like the §12.8 failure report). Off by default per family.
  if (e.target.classList.contains('js-ck-walk')) { const file = e.target.files && e.target.files[0]; if (!file) return; const o = state.overlay; if (!o || o.kind !== 'checklist') return; const isVid = (file.type||'').startsWith('video/'); const reader = new FileReader(); reader.onload = () => { const store = (url) => { const n = IDX.insp.get(o.inspId); if (n) { n.evidence = n.evidence || []; n.evidence.push({ kind: isVid ? 'video' : 'image', url }); logAction(n, isVid ? 'Walkaround video attached' : 'Walkaround photo attached'); saveSoon(); renderOverlay(); } }; if (isVid) store(reader.result); else downscaleImage(reader.result, 1000, 0.6, (out) => store(out || reader.result)); }; reader.onerror = () => toast('Could not read that file.'); reader.readAsDataURL(file); return; }
  if (e.target.classList.contains('js-svc-photo')) {
    const file = e.target.files && e.target.files[0]; if (!file) return;
    if ((file.type || '').startsWith('video/')) { toast('Videos can’t be stored on the record — attach a photo instead.'); return; }
    const reader = new FileReader();
    reader.onload = () => { downscaleImage(reader.result, 600, 0.5, (out) => { if (!out) { toast('Could not read that image.'); return; } state.svcPhoto = out; renderOverlay(); }); };
    reader.onerror = () => toast('Could not read that image.');
    reader.readAsDataURL(file);
    return;
  }
  if (e.target.classList.contains('js-wp-time')) { return setWinTime(e.target.value); }
  if (e.target.classList.contains('js-dp-time')) { return dpTime(e.target.value); }
  if (e.target.classList.contains('js-draftdate')) { return setDraftDate(e.target.dataset.rec, e.target.dataset.which, e.target.value); }
}

/* +New Rental (§0.3 flow, basic): open a draft rental tab + highlight Category→Unit */
/** Logo menu — anchored to the logo (like +New): back-office boards + the Team KPI block. */
function openLogoMenu(anchorEl) {
  const boards = BACKOFFICE_BOARDS.map((b) => `<button class="dd-item js-board" data-board="${b.id}"><span class="mi-ico" style="color:var(--accent);display:inline-flex">${CARD_ICON[b.id] || I.box}</span>${esc(b.title)}<span class="c-count" style="margin-left:auto">${boardRows(b.id).length}</span></button>`).join('');
  // §11 — one ring per ROLE (layout matches the team size), and a single "Sulphur
  // Team" line with the combined score. Per-role breakdown removed (Jac 2026-06-13).
  const roleScores = ROLES.map((role) => { const v = kpiFor(role.id).filter((x) => x != null); return v.length ? Math.round(v.reduce((a, b) => a + b, 0) / v.length) : 0; });
  const teamScore = roleScores.length ? Math.round(roleScores.reduce((a, b) => a + b, 0) / roleScores.length) : 0;
  const tbd = bandColor(teamScore);
  const team = `<div class="menu-sep"></div><div class="menu-team"><div class="menu-team-head">Team KPIs</div><div class="menu-team-ring">${ringsSVG(roleScores, ROLES.map((r) => r.color), { size: 104 })}</div><div class="kpi-list"><div class="kpi-line"><span class="k-name">Sulphur Team</span><span class="k-val" style="color:var(--${tbd.color})">${teamScore}%</span></div></div></div>`;
  const userLine = `<div class="menu-user"><span class="mu-name">${esc(currentUser || 'Signed in')}</span>${currentRole ? `<span class="mu-role">${esc(currentRole)}</span>` : ''}</div>
    <button class="dd-item js-switch-user"><span class="mi-ico" style="display:inline-flex;color:var(--accent)">${I.back}</span>Switch user</button>
    <button class="dd-item js-open-settings"><span class="mi-ico" style="display:inline-flex;color:var(--accent)">${I.grid}</span>Settings${adminUnlocked() ? '' : ' <span class="muted" style="font-size:10px;margin-left:2px">Admin</span>'}</button>
    <div class="menu-sep"></div>`;
  openDropdown(anchorEl, userLine + boards + team);
}
// Switch user — clear this session's password/role (name stays remembered) → login.
function switchUser() {
  document.querySelectorAll('.dropdown-menu').forEach((n) => n.remove());
  backendPassword = ''; currentRole = ''; booting = true;
  sessionStorage.removeItem('jactec.pw'); sessionStorage.removeItem('jactec.role');
  renderLogin();
}
// Settings (Admin-only): manage the role passwords. Admin is already authed with the
// admin password; a staff role must enter it. Loads the live config, then opens the editor.
async function openSettings() {
  document.querySelectorAll('.dropdown-menu').forEach((n) => n.remove());
  const adminPw = adminUnlocked() ? backendPassword : (window.prompt('Settings is Admin-only.\nEnter the Admin password:') || '');
  if (!adminPw) return;
  // Open the shell immediately in a loading state so the wait is visible, not a frozen UI.
  openOverlay({ kind: 'settings', loading: true, adminPw });
  try {
    const r = await backendCall('getConfig', { password: adminPw });
    const o = state.overlay; if (!o || o.kind !== 'settings') return;   // closed while we waited
    if (!r || !r.ok) { closeOverlay(); toast(r && r.error === 'unauthorized' ? 'Wrong Admin password.' : 'Could not open Settings.'); return; }
    o.config = r.config; o.loading = false; renderOverlay();
  } catch (e) { const o = state.overlay; if (o && o.kind === 'settings') closeOverlay(); toast('Could not reach the database.'); }
}
async function saveSettings() {
  const o = state.overlay; if (!o || o.kind !== 'settings') return;
  const root = document.querySelector('.settings-popup .popup-body'); if (!root) return;
  // Logins inputs only exist while the Logins tab is open — when they're absent, keep the
  // passwords from o.config so saving from another tab can't wipe them.
  const haveLogins = !!root.querySelector('.set-input[data-role]');
  let roles = o.config.roles || {}, admin = o.config.admin || '';
  if (haveLogins) {
    roles = {}; root.querySelectorAll('.set-input[data-role]').forEach((i) => { roles[i.dataset.role] = i.value.trim(); });
    admin = root.querySelector('.set-input[data-admin]')?.value.trim() || '';
    // Labels + tiers ride in settings.roleMeta — capture the typed labels, then
    // prune meta for any role that was removed so it can't linger.
    const meta = draftRoleMeta(o);
    root.querySelectorAll('.set-input[data-rolelabel]').forEach((i) => { const id = i.dataset.rolelabel; (meta[id] || (meta[id] = {})).label = i.value.trim(); });
    Object.keys(meta).forEach((id) => { if (!(id in roles)) delete meta[id]; });
    if (!admin || Object.values(roles).some((v) => !v)) { o.error = 'Passwords can\'t be empty.'; o.tab = 'logins'; renderOverlay(); return; }
    if (Object.keys(roles).some((id) => !(meta[id] && meta[id].label))) { o.error = 'Role names can\'t be empty.'; o.tab = 'logins'; renderOverlay(); return; }
  }
  const settings = o.draftSettings || state.settings || {};
  // Inputs are read above; now flip to the Saving… state so the button doesn't look frozen.
  o.saving = true; o.error = ''; renderOverlay();
  try {
    const r = await backendCall('setConfig', { password: o.adminPw, config: { roles, admin, settings } });
    o.saving = false;
    if (r && r.ok) {
      if (haveLogins && adminUnlocked()) { const myNew = currentRole === 'Admin' ? admin : (roles[currentRole] || o.adminPw); backendPassword = myNew; sessionStorage.setItem('jactec.pw', myNew); o.adminPw = myNew; }
      o.config.roles = roles; o.config.admin = admin; o.config.settings = settings;
      persistAdminSettings(settings);   // mirror locally + apply the status overrides live
      closeOverlay(); toast('Settings saved.'); render();
    } else { o.error = 'Save failed.'; renderOverlay(); }
  } catch (e) { o.saving = false; o.error = 'Could not reach the database.'; renderOverlay(); }
}
const addDays = (iso, n) => { const d = parseISO(iso); d.setDate(d.getDate() + n); return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`; };

// §7.1 — guided customer form (validated). Used for BOTH new intake and editing /
// completing an existing customer (opened from the customer card → "Complete account").
function startNewCustomer(prefill) { openCustomerForm(null, prefill); }
/* #3 Quick Add — a compact name+phone create that links straight onto the Quote/
   invoice; "Full intake" hands the typed values to the complete form. (Jac 2026-06-13) */
/* QUICK ADD lives in the Customers search bar (Jac 2026-06-16): a search that
   carries BOTH a name and a phone, on Enter, instantly creates the customer and
   opens it in Standard View — NOT linked to anything (you drag it where it goes).
   Two-entry flow (Jac 2026-06-17, #62): type the name → Enter stages it as a pill
   (no customer yet) → type the phone → Enter combines staged name + phone → create. */
function titleCaseName(s) {
  return (s || '').split(/\s+/).map((w) => (w ? w.charAt(0).toUpperCase() + w.slice(1) : w)).join(' ');
}
function parseQuickCustomer(q) {
  q = (q || '').trim(); if (!q) return null;
  const pm = q.match(/(\+?\d[\d\s().+-]{6,}\d)/);   // a phone-like run (≥8 chars, ends in a digit)
  if (!pm) return null;
  const phone = pm[1].trim();
  if (phone.replace(/\D/g, '').length < 7) return null;   // needs to actually look like a phone
  const name = q.replace(pm[1], ' ').replace(/\s+/g, ' ').trim();
  if (!/[a-zA-Z]/.test(name)) return null;                // …and an actual name
  const parts = name.split(/\s+/);
  return { firstName: parts[0], lastName: parts.slice(1).join(' '), phone };
}
function quickAddCustomerFromSearch(value) {
  const p = parseQuickCustomer(value); if (!p) return false;
  const id = nextCustomerId();
  const c = { customerId: id, firstName: p.firstName, lastName: p.lastName, name: `${p.firstName} ${p.lastName}`.trim(), company: '', phone: p.phone, email: '', address: '', industry: '', accountType: 'Non-Business', payStatus: 'New Customer', requiresPO: false, rentalProtection: false, accountNotes: '', stripeId: '', selfie: '', signature: '', agreementType: '', agreementSignedAt: '', interestedCategoryIds: [], activityLog: [], usedSalesStage: 'N/A', membershipStage: 'N/A', _digest: { activePct: 0, totalPaid: 0, visits: 0, years: 0, avgFrequencyDays: 0, firstInvoice: '', lastInvoice: '' } };
  DATA.customers.push(c); IDX.customer.set(id, c); reindex('customers', c);
  logAction(c, 'Customer quick-added');
  const s = activeSession();
  if (s.cols) s.cols.right = 'customers';
  const ccs = s.cards.customers; ccs.search = ''; ccs.filterTerms = []; ccs.mode = 'standard'; ccs.recId = id; ccs.recType = null; ccs.graphView = false;   // surface the new customer in Standard View — unlinked
  render();
  toast(`${c.name || 'Customer'} added — drag it onto a rental or invoice to link.`);
  return true;
}
/* QUICK ADD — a fruitless Units/Categories search offers a +New button (the empty state).
   It creates the record with the typed text as its name and drops you into its Standard
   view to fill in the rest inline — units/categories are edited inline (no separate form).
   Routed through openStandard so the prior list view is recorded and Back returns to it. */
function nextUnitId() {
  const max = DATA.units.reduce((m, u) => { const n = /^U(\d+)$/.exec(u.unitId || ''); return n ? Math.max(m, +n[1]) : m; }, 0);
  return 'U' + String(max + 1).padStart(3, '0');
}
function quickAddUnitFromSearch(value) {
  const name = (value || '').trim(); if (!name) return false;
  const id = nextUnitId();
  const u = { unitId: id, name, categoryId: '', assignedMechanic: '', currentHours: 0, inspectionStatus: 'Not Ready', fleetStatus: 'Active', purchaseHours: 0, serviceCompletions: {} };
  DATA.units.push(u); IDX.unit.set(id, u); reindex('units', u);
  logAction(u, 'Unit added');
  const cs = activeSession().cards.units; cs.search = ''; cs.filterTerms = [];
  openStandard('units', id);
  toast(`${name} added — set its category, hours, and inspection.`);
  return true;
}
function nextCategoryId() {
  const max = DATA.categories.reduce((m, c) => { const n = /^CAT(\d+)$/.exec(c.categoryId || ''); return n ? Math.max(m, +n[1]) : m; }, 0);
  return 'CAT' + String(max + 1).padStart(3, '0');
}
function quickAddCategoryFromSearch(value) {
  const name = (value || '').trim(); if (!name) return false;
  const id = nextCategoryId();
  const c = { categoryId: id, name, memberDaily: 0, rate1Day: 0, rate7Day: 0, rate4Wk: 0, weekend: 0, msrp: 0, askPrice: 0, bottomDollar: 0, fuelType: '', description: '' };
  DATA.categories.push(c); IDX.category.set(id, c); reindex('categories', c);
  logAction(c, 'Category added');
  const cs = activeSession().cards.categories; cs.search = ''; cs.filterTerms = [];
  openStandard('categories', id);
  toast(`${name} added — set its day/week/month rates.`);
  return true;
}
/** Turn a customer-search string into prefill: a letterless string → phone, else
 *  split on the first space into first/last (how staff usually type a name). */
function parseCustomerSearch(q) {
  q = (q || '').trim(); if (!q) return {};
  if (/\d/.test(q) && !/[a-zA-Z]/.test(q)) return { phone: q };
  const parts = q.split(/\s+/);
  return parts.length >= 2 ? { firstName: parts[0], lastName: parts.slice(1).join(' ') } : { firstName: q };
}
/* `linkTo` { card:'rentals'|'invoices', recId } — the standing quick-add-link
   contract (Wave 2): the moment the new customer exists it is LINKED to that
   record via the surviving wrappers; existing customers get DRAGGED on instead. */
function openCustomerForm(editId, prefill, linkTo) {
  const c = editId ? IDX.customer.get(editId) : null;
  const f = (k, d) => (c && c[k] != null ? c[k] : ((prefill && prefill[k]) || d || ''));
  openOverlay({ kind: 'newCustomer', error: '', editId: editId || null, linkTo: (!editId && linkTo) || null, draft: {
    firstName: f('firstName'), lastName: f('lastName'), company: f('company'), phone: f('phone'),
    email: f('email'), industry: f('industry'), accountType: f('accountType', 'Non-Business'),
    requiresPO: c ? !!c.requiresPO : undefined, rentalProtection: c ? !!c.rentalProtection : undefined, accountNotes: f('accountNotes'), selfie: f('selfie'), signature: f('signature'),
    agreementType: f('agreementType'), agreementSignedAt: f('agreementSignedAt'),
    idNumber: f('idNumber'), netDays: f('netDays'), custom: (c && c.custom) ? { ...c.custom } : {},
  } });
}
// Downscale + JPEG-compress an image data URL so it fits inside one Sheet cell
// (Google caps cells at ~50k chars). cb receives the compressed data URL.
function downscaleImage(dataUrl, maxDim, quality, cb) {
  const img = new Image();
  img.onload = () => {
    let w = img.width, h = img.height; const s = Math.min(1, maxDim / Math.max(w, h));
    w = Math.max(1, Math.round(w * s)); h = Math.max(1, Math.round(h * s));
    const cv = document.createElement('canvas'); cv.width = w; cv.height = h;
    cv.getContext('2d').drawImage(img, 0, 0, w, h);
    cb(cv.toDataURL('image/jpeg', quality));
  };
  img.onerror = () => cb('');
  img.src = dataUrl;
}
const NC_INDUSTRIES = ['Construction', 'Concrete', 'Welding', 'Electrical', 'Plumbing', 'Roofing', 'Painting', 'Landscaping', 'Trucking', 'Industrial', 'Oil & Gas', 'Real Estate', 'Entertainment', 'Agriculture'];
const NC_ACCOUNT_TYPES = ['Non-Business', 'Business', 'Non-Business Member', 'Business Member'];
/** Next sequential customer id (C0001 format), one past the current max. */
function nextCustomerId() {
  const max = DATA.customers.reduce((m, c) => { const n = /^C(\d+)$/.exec(c.customerId || ''); return n ? Math.max(m, +n[1]) : m; }, 0);
  return 'C' + String(max + 1).padStart(4, '0');
}
