// Safety net: a debounced save that hasn't flushed yet — or a large bulk-import sync
// still in flight — would be lost silently if the page closes/reloads first (#164).
// If anything is still un-persisted, kick a final flush and let the browser show its
// "unsaved changes" prompt so the operator can't drop records without noticing.
window.addEventListener('beforeunload', (e) => {
  if (booting || !backendPassword || !lastSaved) return;   // demo/offline: nothing to persist
  if (!saving && !savePending && !computeChanges().n) return;   // everything's already saved → leave quietly
  flushSave();
  e.preventDefault(); e.returnValue = '';
});
function renderLogin(msg) {
  $('#app').innerHTML = `<div class="login-screen"><video id="login-video" class="login-video" src="assets/login-intro.mp4?v=20260623l" muted loop playsinline preload="auto" aria-hidden="true"></video><form class="login-box" id="login-form">
    <span class="rivet tl"></span><span class="rivet tr"></span><span class="rivet bl"></span><span class="rivet br"></span>
    <div class="login-plate">
      <img class="login-logo" src="assets/jac-rentals-logo.jpg" alt="Jac Rentals" />
      <div class="login-title">Rental Wrangler</div>
      <div class="login-sub">JacRentals · Sulphur, LA</div>
      <div class="login-field">
        <label class="login-lbl" for="login-name">Operator</label>
        <input id="login-name" class="login-input" placeholder="Your name" autocomplete="name" value="${esc(currentUser)}" />
      </div>
      <div class="login-field">
        <label class="login-lbl" for="login-pw">Team password</label>
        <input id="login-pw" type="password" class="login-input" placeholder="••••••••" autocomplete="current-password" />
      </div>
      <button type="submit" class="login-btn" data-r="R17" id="login-go">Clock In</button>
      <div class="login-err" id="login-err">${msg ? esc(msg) : ''}</div>
    </div>
  </form></div>`;
  document.getElementById('login-form').addEventListener('submit', (e) => { e.preventDefault(); attemptLogin(); });
  document.getElementById(currentUser ? 'login-pw' : 'login-name').focus();
}
function finishLoad() {
  snapshotSaved();                                              // baseline = what the backend currently holds
  buildIndexes(); state.cascade = createCascade(DATA); booting = false; render();
  loadGlobalViews();                                            // pull the shared, company-wide view set
  loadChats();                                                  // pull the shared team-chat threads (§ team-chat sync)
  wranglerRailLoad();                                           // load the Mr. Wrangler rail from IndexedDB (+ one-time localStorage migration)
  refreshWranglerRequests();                                    // §18e populate the approval-inbox badge
  refreshWranglerNotifications();                               // §18f populate the notification-bell badge
  startRefreshPoll();                                           // live multi-user: poll for others' changes (§ refreshFromBackend)
  if (migrationDirty) { migrationDirty = false; saveSoon(); }   // push parsed first/last names up to the Sheet
  // #edit=<id> — desktop→phone handoff opens that customer's account form (§7.1).
  const em = (location.hash || '').match(/edit=([\w-]+)/i);
  if (em && IDX.customer.get(em[1])) { history.replaceState(null, '', location.pathname + location.search); openCustomerForm(em[1]); }
  // #migrate-units — admin: round up rentals' free-text legacy unit names into real records.
  if ((location.hash || '').toLowerCase().includes('migrate-units')) {
    history.replaceState(null, '', location.pathname + location.search);   // self-clear so a refresh can't re-fire
    if (adminUnlocked()) openMigrationPreview(); else toast('Admin unlock required to round up missing units.');
  }
  // #s=<id> — H1 session sharing: restore the open tabs saved by another device's QR.
  const sm = (location.hash || '').match(/[#&]s=([\w-]+)/i);
  if (sm) {
    history.replaceState(null, '', location.pathname + location.search);
    backendCall('getSession', { sid: sm[1] }).then((r) => {
      let p; try { p = r && r.ok && r.data ? JSON.parse(r.data) : null; } catch (e) { p = null; }
      if (!p || !Array.isArray(p.tabs)) { toast('That shared session has expired.'); return; }
      p.tabs.forEach((t) => { if (recOf(entityCardOf(t.card, t.recType), t.recId)) openInNewTab(t.card, t.recId, t.recType); });
      if (state.tabs.length) { state.activeTabId = state.tabs[Math.min(p.activeIdx || 0, state.tabs.length - 1)].id; render(); toast(`Opened ${state.tabs.length} shared tab${state.tabs.length === 1 ? '' : 's'}.`); }
    }).catch(() => toast('Could not load the shared session.'));
  }
}
// H1 — Share session: stash the open tabs in the backend and show a QR that carries the id,
// so another device (signed in with the shared password) restores the same open records.
async function shareSession() {
  const tabs = state.tabs.map((t) => ({ card: t.card, recId: t.recId, recType: t.recType || null }));
  let url = location.origin + location.pathname;
  if (typeof backendPassword !== 'undefined' && backendPassword && tabs.length) {
    const sid = 'S' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
    try { const r = await backendCall('saveSession', { sid, data: JSON.stringify({ tabs, activeIdx: Math.max(0, state.tabs.findIndex((t) => t.id === state.activeTabId)) }) });
      if (r && r.ok) url += '#s=' + sid; } catch (e) { /* fall back to the plain app URL */ }
  }
  openOverlay({ kind: 'qr', title: 'Open on another device', url,
    caption: tabs.length ? `Scan to open your ${tabs.length} open tab${tabs.length === 1 ? '' : 's'} on another device — sign in with the shared password.`
      : 'Scan to open Rental Wrangler on another device — sign in with the shared password.' });
}
// Shop roles (Mechanic / M.Tech) get the Shop card + its 3-bar graph as the landing view
// — quick access to the crew's worklist. A default only; they can navigate anywhere after.
function applyShopRoleLanding() {
  if (currentRole !== 'mechanic' && currentRole !== 'mtech') return;
  const s = activeSession(); if (!s) return;
  if (s.cols) s.cols.left = 'shop';
  const sc = s.cards.shop; if (sc) { sc.segment = 'all'; sc.graphView = true; sc.mode = 'list'; sc.recId = null; sc.recType = null; }
  const li = COLUMNS.findIndex((c) => c.id === 'left'); if (li >= 0) state.mobileCol = li;   // phone: make the Shop column the active one
  render();
}
async function attemptLogin() {
  const name = (document.getElementById('login-name')?.value || '').trim();
  const pw = document.getElementById('login-pw')?.value || '';
  if (!name) { const errEl = document.getElementById('login-err'); if (errEl) errEl.textContent = 'Please enter your name (edits are logged under it).'; document.getElementById('login-name')?.focus(); return; }
  if (!pw) return;
  backendPassword = pw;
  const btn = document.getElementById('login-go'); if (btn) { btn.textContent = 'Signing in…'; btn.disabled = true; }
  // Roll the Mr. Wrangler intro behind the box while the (slow) backend load runs — a little entertainment for the wait.
  const screen = document.querySelector('.login-screen'); if (screen) screen.classList.add('signing-in');
  const vid = document.getElementById('login-video'); if (vid) { try { const p = vid.play(); if (p && p.catch) p.catch(() => {}); } catch (e) {} }
  try {
    // Ask the backend for the role. The role-aware backend returns it; an older
    // backend (pre-roles) replies "unknown action" → we proceed without a role
    // (single-password mode). loadFromBackend then validates the password either way.
    let role = '';
    try {
      const a = await backendCall('auth');
      if (a && a.ok) role = a.role || '';
      else if (a && /unauthorized/i.test(a.error || '')) throw new Error('unauthorized');
    } catch (e2) { if (/unauthorized/i.test(e2.message || '')) throw e2; }
    currentRole = role;
    currentUser = name;
    try { localStorage.setItem('jactec.user', name); } catch {}
    try { sessionStorage.setItem('jactec.role', role); } catch {}
    sessionStorage.setItem('jactec.pw', pw);
    await loadFromBackend();
    finishLoad();
    applyShopRoleLanding();   // shop roles (Mechanic / M.Tech) land on the Shop graph
  } catch (e) {
    backendPassword = ''; sessionStorage.removeItem('jactec.pw'); sessionStorage.removeItem('jactec.role');
    renderLogin(/unauthorized/i.test(String(e && e.message)) ? 'That password wasn’t recognized.' : "Couldn't reach the database. Check your connection and try again.");
  }
}

// §M0 — reflect the viewport width onto <body> so CSS + the gesture layer can key off
// it (is-phone = 1 column, is-narrow = 2 columns; neither = desktop 3 columns).
function applyViewportClass() {
  document.body.classList.toggle('is-phone', window.matchMedia('(max-width: 640px)').matches);
  document.body.classList.toggle('is-narrow', window.matchMedia('(max-width: 1024px)').matches);
}
function boot() {
  // Recovery hatch: app.jacrentals.com/#reset-settings (or #safe-mode) wipes saved customizations
  // before they apply — the guaranteed way back if a bad setting ever breaks the screen.
  try {
    const h = (location.hash || '').toLowerCase();
    if (h.includes('reset-settings') || h.includes('safe-mode')) { localStorage.removeItem('jactec.settings'); localStorage.removeItem('jactec.settings.prev'); state.settings = {}; settingsReverted = true; }
  } catch (e) {}
  applySettings();   // Settings Board: apply admin status overrides (color/icon) before the first render
  if (settingsReverted) setTimeout(() => { try { toast('Customizations reset to defaults (recovery mode).'); } catch (e) {} }, 800);
  initTooltip();
  applyViewportClass();
  const onVP = () => { applyViewportClass(); if (!booting) render(); };
  window.matchMedia('(max-width: 640px)').addEventListener('change', onVP);
  window.matchMedia('(max-width: 1024px)').addEventListener('change', onVP);
  // §M3 — Android hardware-back / swipe-back closes the topmost sheet instead of
  // leaving the app. backConsuming = our own balancing history.back(), so ignore it.
  window.addEventListener('popstate', () => {
    if (backConsuming) { backConsuming = false; return; }
    if (anyDismissable()) { backGuard = false; dismissTopSheet(); }   // entry already popped by the browser → re-pushed by render if more remain
  });
  // §M1/§M3 — phone horizontal swipes. On the FOOTER dock: change column (the only place
  // columns change now). On the GRID/column: Back/Forward of the active card. A real drag
  // (long-press then move) is excluded; a fired swipe swallows the trailing click.
  let swipeStart = null;
  document.addEventListener('pointerdown', (e) => {
    if (!document.body.classList.contains('is-phone')) { swipeStart = null; return; }
    const inFooter = !!(e.target.closest && e.target.closest('.mobile-dock'));
    const inGrid = !inFooter && !!(e.target.closest && e.target.closest('.grid'));
    swipeStart = (inFooter || inGrid) ? { x: e.clientX, y: e.clientY, id: e.pointerId, footer: inFooter } : null;
  }, true);
  document.addEventListener('pointerup', (e) => {
    const s = swipeStart; swipeStart = null;
    if (!s || e.pointerId !== s.id || DRAG.active || DRAG.suppressClick) return;   // a real drag is not a swipe
    const dx = e.clientX - s.x, dy = e.clientY - s.y;
    if (Math.abs(dx) < 55 || Math.abs(dx) < Math.abs(dy) * 1.3) return;            // not a clean horizontal swipe
    swipeFired = true;                                                             // swallow the trailing click (row/toggle)
    if (s.footer) {
      const cur = currentMobileMember(); let i = MOBILE_CARDS.indexOf(cur); if (i < 0) i = 0;   // left → next card, right → previous
      const next = Math.max(0, Math.min(MOBILE_CARDS.length - 1, i + (dx < 0 ? 1 : -1)));
      if (next !== i) { goToCard(MOBILE_CARDS[next]); haptic(8); }
    } else {
      const card = activeMobileCard();
      if (dx > 0) cardBack(card); else cardFwd(card);                              // swipe right → Back, left → Forward
      haptic(8);
    }
  }, true);
  initDrag();   // §15c drag & drop link engine — #drag-layer singleton + document pointer listeners
  try { loadGoogleMaps(); } catch (e) {}   // §2.3 warm the Maps SDK at boot so the dispatch cockpit + transport editor open instantly (no first-open wait / "load it twice")
  // R0 flash-lint: ON by default — violations self-report by pulsing (SPEC v8)
  try { if (localStorage.getItem('jactec.lint') !== '0') document.body.classList.add('rw-lint'); } catch (err) {}
  document.addEventListener('click', onClick);
  document.addEventListener('input', onInput);
  document.addEventListener('change', onChange);
  // §12.1 action entry v3 — Enter commits + field stays open (rapid entry);
  // click-away commits + closes; Esc closes without committing. The render()
  // inside a commit detaches the focused input → fires focusout; actBusy guards
  // that programmatic blur so it can't double-commit (the old crash).
  let actBusy = false;
  document.addEventListener('keydown', (e) => {
    if (!e.target.classList?.contains('js-act-in')) return;
    const rec = e.target.dataset.rec;
    if (e.key === 'Enter') {
      e.preventDefault();
      const val = e.target.value; e.target.value = '';   // clear BEFORE commit so the blur sees empty
      actBusy = true; commitAction(rec, val, true); actBusy = false;   // keepOpen
    } else if (e.key === 'Escape') {
      e.preventDefault(); e.stopPropagation();
      e.target.value = ''; actBusy = true; state.actOpen = null; render(); actBusy = false;
    }
  });
  document.addEventListener('focusout', (e) => {
    if (actBusy || !e.target.classList?.contains('js-act-in')) return;
    const v = e.target.value.trim();
    actBusy = true; commitAction(e.target.dataset.rec, v, false); actBusy = false;
  });
  // Jac: pressing Enter in the +Part/Task box confirms "Add line".
  document.addEventListener('keydown', (e) => {
    if (state.overlay?.kind !== 'partform') return;
    if (e.key === 'Enter' && e.target.matches && e.target.matches('.js-pf2-desc, .js-pf2-cost, .js-pf2-hours, .js-pf2-url, .js-pf2-vendor')) { e.preventDefault(); savePartForm(); }
  });
  // §2.3 dispatch route reorder — native drag, self-contained (re-render only on drop,
  // so the grid's custom pointer engine isn't involved). Reorders the day's run.
  let dispDragId = null;   // §2.3 cockpit rail: drag a stop token up/down to set the run order (overrides time-sort)
  document.addEventListener('dragstart', (e) => { const s = e.target.closest && e.target.closest('.js-disp-tok'); if (s) { dispDragId = s.dataset.id; if (e.dataTransfer) { e.dataTransfer.effectAllowed = 'move'; try { e.dataTransfer.setData('text/plain', s.dataset.id); } catch (x) {} } s.classList.add('disp-dragging'); const rail = s.closest('.disprail'); if (rail) rail.classList.add('dragging'); } });   // pin the rail OPEN for the whole drag (hover is lost mid-drag)
  document.addEventListener('dragover', (e) => { if (dispDragId && e.target.closest && e.target.closest('.disprail')) e.preventDefault(); });
  document.addEventListener('drop', (e) => {
    const rail = e.target.closest && e.target.closest('.disprail'); if (!dispDragId || !rail) return; e.preventDefault();
    const ids = [...rail.querySelectorAll('.js-disp-tok')].map((n) => n.dataset.id);
    const over = e.target.closest('.js-disp-tok');
    const from = ids.indexOf(dispDragId); if (from !== -1) ids.splice(from, 1);
    const to = over && over.dataset.id !== dispDragId ? ids.indexOf(over.dataset.id) : ids.length;
    ids.splice(to < 0 ? ids.length : to, 0, dispDragId);
    const ord = dispatchOrderLS(); ord[rail.dataset.day] = ids; _lsSave('jactec.dispatchOrder', ord);
    state.dispFocusId = dispDragId; dispDragId = null; render();   // keep the moved stop highlighted so it stays trackable after the reorder
  });
  document.addEventListener('dragend', () => { dispDragId = null; document.querySelectorAll('.disp-dragging').forEach((n) => n.classList.remove('disp-dragging')); document.querySelectorAll('.disprail.dragging').forEach((n) => n.classList.remove('dragging')); });
  // §2.3 route arrows — keyboard parity: Enter/Space arms or lands a leg; Escape cancels the draw.
  document.addEventListener('keydown', (e) => {
    const pt = e.target.closest && e.target.closest('.js-disp-arrowpt');
    if (pt && (e.key === 'Enter' || e.key === ' ')) {
      e.preventDefault(); const route = pt.closest('.js-disp-route');
      return dispatchArrowClick(route ? route.dataset.day : (state.dispatchDay || TODAY_ISO), pt.dataset.node);
    }
    if (e.key === 'Escape' && state.dispArm != null) { e.preventDefault(); e.stopPropagation(); state.dispArm = null; render(); }
    // §20 route-rail: keyboard-activate a stop, Esc disarms the pending route pick
    const rn = e.target.closest && e.target.closest('.js-tnode');
    if (rn && (e.key === 'Enter' || e.key === ' ')) { e.preventDefault(); return armTransportNode(rn.dataset.rec, rn.dataset.unit || null, rn.dataset.node); }
    if (e.key === 'Escape' && state.transportArm != null) { e.preventDefault(); e.stopPropagation(); state.transportArm = null; render(); }
  });
  document.addEventListener('mousemove', onInspectMove);   // Design Inspector hover tag (no-op unless state.inspect)
  document.addEventListener('mousemove', caScrub);          // D2 — customer activity chart cursor scrub
  // Board View formula cells: reveal the raw "=…" on focus, recompute on blur.
  document.addEventListener('focusin', (e) => {
    const t = e.target; if (t && t.classList && t.classList.contains('bv-scratch') && t.dataset.raw) t.textContent = t.dataset.raw;
  });
  document.addEventListener('focusout', (e) => {
    const t = e.target; const o = state.overlay; if (!t || !t.classList || o?.kind !== 'boardview') return;
    // a scratch/notes cell: compute IN PLACE (no full re-render → focus isn't stolen).
    if (t.classList.contains('bv-scratch')) {
      const v = (t.textContent || '').trim();
      if (v.startsWith('=')) {
        const session = activeSession(), entity = boardEntity(o.card, session);
        const cols = cardColumns(o.card, session), recs = boardViewRecords(o, session);
        const rec = t.dataset.row ? recs.find((r) => String(idOf(entity, r)) === t.dataset.row) || null : null;   // data-row cell → that row; scratch row → aggregate
        const r = bvCompute(v.slice(1), cols, recs, rec);
        t.dataset.raw = v; t.classList.add('bv-comp'); t.textContent = r.err ? 'ERR' : bvFmtNum(r.val);
      } else if (t.dataset.raw) { t.removeAttribute('data-raw'); t.classList.remove('bv-comp'); }
      return;
    }
    // a formula-column header changed → recompute that whole column + footer.
    if (t.classList.contains('bv-colname') && (t.value || '').trim().startsWith('=')) renderOverlay();
  });
  document.addEventListener('keydown', (e) => {
    // Esc exits the Design Inspector first (SPEC v8)
    if (e.key === 'Escape' && state.inspect) {
      state.inspect = false; document.body.classList.remove('rw-inspect');
      const tip = document.getElementById('rw-tip'); if (tip) tip.style.display = 'none';
      toast('Inspector off.'); render(); return;
    }
    // §5.4 — the search bar IS the filter builder: Enter locks the current text in as
    // an AND-narrowing pill (clearing the input), Backspace-on-empty pops the last pill.
    if (e.target.id === 'globalsearch') {
      if (e.key === 'Enter') { e.preventDefault(); addFilterTerm('global', e.target.value); return; }
      if (e.key === 'Backspace' && !e.target.value && state.filterTerms.length) { e.preventDefault(); removeFilterTerm('global', state.filterTerms.length - 1); return; }
      return;
    }
    // §5.4 (per-card) — same Enter-to-pin / Backspace-to-pop on a card's list search.
    if (e.target.classList.contains('mini-search') && e.target.dataset.card && !e.target.classList.contains('js-history-search')) {
      const card = e.target.dataset.card; const cs = activeSession().cards[card];
      if (e.key === 'Enter') {
        e.preventDefault();
        if (card === 'customers') {
          // #62 two-entry quick-add: fold any staged name pill(s) into this entry (the
          // phone) so name+phone across two Enters creates the customer. Staged terms are
          // lowercased by addFilterTerm, so title-case the name half before parsing.
          const staged = (cs.filterTerms || []).map((ft) => ft.t).join(' ').trim();
          const combined = staged ? `${titleCaseName(staged)} ${e.target.value}`.trim() : e.target.value;
          if (quickAddCustomerFromSearch(combined)) return;
        }
        addFilterTerm(card, e.target.value); return;
      }
      if (e.key === 'Backspace' && !e.target.value && (cs.filterTerms || []).length) { e.preventDefault(); removeFilterTerm(card, cs.filterTerms.length - 1); return; }
      return;
    }
    if (e.target.classList.contains('nc-in') && e.key === 'Enter' && e.target.tagName !== 'SELECT') { e.preventDefault(); return saveNewCustomer(); }
    if (e.target.classList.contains('js-wr-in') && e.key === 'Enter') { e.preventDefault(); return wranglerSend(); }   // §18
    if (e.target.classList.contains('chat-input') && e.key === 'Enter') { e.preventDefault(); return chatSend(); }
    // §M3 — one predictable back/dismiss chain (shared with the Android back button):
    // winpicker → overlay → Mr. Wrangler dock → team chat dock.
    if (e.key === 'Escape') dismissTopSheet();
  });
  // mouse hotkeys (§0.1): double-click a row = anchor; right-click = Back
  const hotkeyGuard = (e) => e.target.closest('.inline-edit, input, textarea, select, .pill, button, .x') || state.winEdit;
  document.addEventListener('dblclick', (e) => {
    if (hotkeyGuard(e)) return;
    if (e.target.closest('.row')) return;                 // rows are handled by the click discriminator (#10)
    const r = cardRecordAt(e.target); if (!r) return;     // dbl-click on a card's open detail → anchor it (or un-anchor if it's already the anchor)
    e.preventDefault(); window.getSelection()?.removeAllRanges();
    anchorOrToggle(r.card, r.recId, r.recType);
  });
  // right-click = send the card to its List View; double right-click = drop the anchor.
  document.addEventListener('contextmenu', (e) => {
    if (e.target.closest('input, textarea, .inline-input')) return;            // allow native menu in fields
    // Right-click WINS over the hover preview (Jac): a floated preview sits under the
    // cursor and stole the event (it lives on <body>, outside .card), so the menu /
    // card-to-List never fired. Dismiss it and re-resolve the row beneath the cursor.
    let target = e.target;
    if (target.closest('.hover-preview')) { hideHoverPreview(); target = document.elementFromPoint(e.clientX, e.clientY) || target; }
    if (!target.closest('.card') && !target.closest('.overlay .popup')) return;
    e.preventDefault();
    if (performance.now() - lastTouchCtx < 700) return;                        // §M3 — our touch long-press already opened it; swallow the trailing native event
    hideHoverPreview();                                                        // clear any preview still mid-fuse so it can't reappear over the menu
    openCtxMenuAt(target, e.clientX, e.clientY);                               // §R20 leaf → Wrangler menu; card dead-space → card-to-List (single) / clear-anchor (double)
  });
  document.addEventListener('mousemove', (e) => { lastMouse.x = e.clientX; lastMouse.y = e.clientY; });
  // hover preview (#1): float a record's Standard view after a short hover on a row/pill
  document.addEventListener('mouseover', (e) => {
    if (!state.previewsOn || DRAG.active) return;       // previews off (per device) — and NEVER mid-drag (§15c)
    if (e.target.closest('.hover-preview')) return;     // hovering INSIDE the open preview must NOT re-trigger/close it — let it persist so you can scroll/interact (the preview's own mouseenter/leave manage it)
    // interactive controls are CLICK targets, not preview triggers — the popup kept
    // landing under the cursor while aiming at the status dropdown (Jac 2026-06-12).
    // The row EYE is the one button that IS a preview trigger.
    if (!e.target.closest('.js-roweye') && (e.target.closest('.pill.gate, .js-status-pill, button, .x, .seg, .add-field, .dropdown-menu') || document.querySelector('.dropdown-menu'))) { clearTimeout(hoverTimer); return; }
    const t = hoverTarget(e.target);
    if (!t || state.overlay || state.winEdit) return;
    clearTimeout(hoverGrace);            // re-entering a row cancels a pending close
    if (t === hoverEl) return;
    hoverEl = t; hideHoverPreview();
    // the row EYE is a deliberate "show me" target → fast; pills keep the longer fuse.
    // Halved 2026-06-12 (Jac: "I feel more in control of it now").
    hoverTimer = setTimeout(() => { if (hoverEl === t) showHoverPreview(t); }, t.classList?.contains('js-roweye') ? 190 : 500);
  });
  document.addEventListener('mouseout', (e) => {
    if (!hoverEl) return;
    // Only react when the mouse actually LEAVES the previewed row (or the preview node).
    // This is a document-level listener, so unrelated mouseouts bubble up too — and if we
    // acted on those, each one kept rescheduling the close timer past the preview delay,
    // so a quick graze of the first row would still pop its preview after the mouse left.
    if (!((hoverEl.contains && hoverEl.contains(e.target)) || (hoverNode && hoverNode.contains && hoverNode.contains(e.target)))) return;
    const to = e.relatedTarget;
    // keep it alive if the mouse moved within the row OR onto the preview itself (to scroll it)
    if (to && ((hoverEl.contains && hoverEl.contains(to)) || (hoverNode && hoverNode.contains && hoverNode.contains(to)))) return;
    // grace window: leaving the row toward the preview doesn't kill it instantly — the
    // preview's own mouseenter (showHoverPreview) cancels this timer once the mouse lands.
    clearTimeout(hoverGrace);
    hoverGrace = setTimeout(() => { hoverEl = null; hideHoverPreview(); }, 320);
  });
  // Admin / offline boot modes (opt-in via URL hash) — checked before the login gate.
  const hash = (location.hash || '').toLowerCase();
  if (hash.includes('local')) { return offlineBoot(); }     // #local — render from data.js, no backend
  if (hash.includes('reseed')) { return reseedFromFile(); }  // #reseed — REPLACE live data with the file

  // §16 — gate on the shared password: load from the backend if we already have it
  // this session, otherwise show the login screen. The app only renders once data is in.
  if (backendPassword) {
    loadFromBackend().then(finishLoad)
      .catch(() => { backendPassword = ''; sessionStorage.removeItem('jactec.pw'); renderLogin('Please sign in again.'); });
  } else {
    renderLogin();
  }
}

// #local — render straight from data.js with NO backend (offline/demo + dev smoke test).
// saveSoon() already no-ops without a password, so edits stay in-memory only.
function offlineBoot() { buildIndexes(); state.cascade = createCascade(DATA); seedDemoRequests(); booting = false; render(); exposeTestApi(); wranglerRailLoad(); }
/* #local demo only: a sample Requests-inbox entry so the review/continue flow is
   visible without a backend. Real installs fetch live requests via the backend. */
function seedDemoRequests() {
  if (wranglerRequests.length) return;
  const ph = (label, c) => `data:image/svg+xml;utf8,${encodeURIComponent(`<svg xmlns='http://www.w3.org/2000/svg' width='160' height='160'><rect width='160' height='160' fill='${c}'/><rect x='14' y='14' width='132' height='30' rx='6' fill='rgba(255,255,255,.18)'/><rect x='14' y='58' width='96' height='14' rx='4' fill='rgba(255,255,255,.28)'/><rect x='14' y='80' width='120' height='14' rx='4' fill='rgba(255,255,255,.2)'/><text x='14' y='140' fill='rgba(255,255,255,.7)' font-family='sans-serif' font-size='13'>${label}</text></svg>`)}`;
  wranglerRequests.push({
    number: 41, url: '#', title: 'Inspection “Ready” pill clashes with “On Rent” green',
    labels: ['wrangler-request'],   // Needs your OK
    images: [ph('screenshot.png', '#1f5f48'), ph('zoomed.png', '#2a4d6e')],
    body: [
      '_Filed by Mr. Wrangler from in-app chat._', '',
      "### Requested change (Mr. Wrangler's write-up)",
      'On the Units card the inspection “Ready” pill renders the same green as a rental’s “On Rent” status, so at a glance they blur together. Request: give inspection-Ready its own distinct tone so it doesn’t read like a rental status.', '',
      '> 📎 You can paste or drag a screenshot right here before submitting.', '',
      '### Conversation',
      '**Reporter**: The green Ready tag looks exactly like On Rent. Can we make them different so I can tell them apart?', '',
      '**Mr. Wrangler**: Good eye — “Ready” (inspection) and “On Rent” (rental) both come out green, so they run together. I’ll propose a distinct tone for inspection-Ready and keep On Rent as the rental green.', '',
      '### Repro context', '- **View:** list view', '- **Role:** Admin', '',
      "_A request for the developer's OK — NOT auto-implemented._",
    ].join('\n'),
  });
  wranglerRequests.push({
    number: 43, url: '#', title: 'Add a “snooze service” button on the unit card',
    labels: ['wrangler-needs-jac'],   // build paused — Mr. Wrangler needs an answer
    body: [
      '_Filed by Mr. Wrangler from in-app chat._', '',
      '### Approved plan (build to this) (Mr. Wrangler\'s write-up)',
      '1. Add a “Snooze 7 days” button to the service-due banner on the unit card.\n2. Push the service countdown out by the snoozed days.\n3. Show a small “snoozed” note until the new date.', '',
      '### Conversation',
      '**Reporter**: Let’s let me snooze a service reminder for a week.', '',
      '**Mr. Wrangler**: Here’s the plan — a “Snooze 7 days” button on the service banner that pushes the countdown out. Build it?', '',
      '**Reporter**: Yes, build it.', '',
      '**Mr. Wrangler**: One thing before I ship — should a snooze also pause the “Past Due” red flag, or keep the flag and just move the date? It changes how overdue units read on the board.', '',
      '### Repro context', '- **View:** units', '- **Role:** Admin',
    ].join('\n'),
  });
  reqLoaded = true;
}
